+import type { BaseIssue, BaseSchema, InferIssue } from '../../types/index.ts';
+import { lazy } from '../../schemas/lazy/index.ts';
+import type { Recur, RecursiveInput, RecursiveOutput } from './types.ts';
+
+/**
+ * Recursive schema interface.
+ */
+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    RecursiveInput<TWrapped>,
+    RecursiveOutput<TWrapped>,
+    InferIssue<TWrapped>
+  > {
+  /**
+   * The schema type.
+   */
+  readonly type: 'recursive';
+  /**
+   * The schema reference.
+   */
+  readonly reference: typeof recursive;
+  /**
+   * The wrapped schema.
+   */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * Recursive schema placeholder.
+ */
+export const Recur: Recur = {
+  kind: 'schema',
+  type: 'recur',
+  reference: () => Recur,
+  expects: 'unknown',
+  async: false,
+  '~standard': undefined as never,
+  '~run': undefined as never,
+};
+
+/**
+ * Creates a recursive schema.
+ *
+ * @param schema The schema containing recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
+  schema: TWrapped
+): RecursiveSchema<TWrapped> {
+  let recursiveSchema: RecursiveSchema<TWrapped>;
+  recursiveSchema = _replaceRecur(schema, () => lazy(() => recursiveSchema)) as RecursiveSchema<TWrapped>;
+  return recursiveSchema;
+}
+
+/**
+ * Replaces recursive placeholders in a schema graph.
+ *
+ * @param value The value to process.
+ * @param createRecur The recursive schema factory.
+ *
+ * @returns The processed value.
+ *
+ * @internal
+ */
+export function _replaceRecur<TValue>(
+  value: TValue,
+  createRecur: () => BaseSchema<unknown, unknown, BaseIssue<unknown>>
+): TValue {
+  const values = new WeakMap<object, object>();
+
+  function replace(value: unknown): unknown {
+    if (value === Recur) {
+      return createRecur();
+    }
+    if (!value || typeof value !== 'object') {
+      return value;
+    }
+    const previous = values.get(value);
+    if (previous) {
+      return previous;
+    }
+    if (Array.isArray(value)) {
+      const array: unknown[] = [];
+      values.set(value, array);
+      for (const item of value) {
+        array.push(replace(item));
+      }
+      return array;
+    }
+    const object = Object.create(Object.getPrototypeOf(value)) as Record<PropertyKey, unknown>;
+    values.set(value, object);
+    for (const key of Reflect.ownKeys(value)) {
+      const descriptor = Object.getOwnPropertyDescriptor(value, key)!;
+      if ('value' in descriptor) {
+        descriptor.value = replace(descriptor.value);
+      }
+      Object.defineProperty(object, key, descriptor);
+    }
+    return object;
+  }
+
+  return replace(value) as TValue;
+}
